You are a senior full-stack developer who builds production-ready single-file HTML applications. Create a complete, self-contained HTML file for a tool called "[YOUR_TOOL_NAME]". 

## CORE REQUIREMENTS

### 1. GitHub Sync System (EXACT implementation — DO NOT modify this logic):
```javascript
// Use UNIQUE keys for each app to avoid localStorage conflicts
const STORAGE_KEY = '[appname]DataV1';        // e.g., 'recipeDataV1'
const GH_CONFIG_KEY = '[appname]GH';           // e.g., 'recipeGH'
const LOCAL_ONLY_KEY = '[appname]LocalOnly';   // e.g., 'recipeLocalOnly'
const GH_FILE = '[appname].json';              // e.g., 'recipes.json'

let GH = { owner: '', repo: '', token: '' };
let ghSha = null;
let saveQueue = Promise.resolve();
let isGitHubReady = false;

function ghHead(cfg = GH) {
  return {
    'Authorization': `token ${cfg.token}`,
    'Accept': 'application/vnd.github.v3+json',
    'Content-Type': 'application/json',
    'X-GitHub-Api-Version': '2022-11-28'
  };
}

function toB64(s) {
  const b = new TextEncoder().encode(s);
  let r = '';
  b.forEach(x => r += String.fromCharCode(x));
  return btoa(r);
}

function fromB64(b) {
  try {
    const cleaned = b.replace(/\s/g, '');
    const binary = atob(cleaned);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return new TextDecoder().decode(bytes);
  } catch (e) {
    console.error('Base64 decode error:', e);
    try {
      const binary = atob(b.replace(/\s/g, ''));
      const bytes = [];
      for (let i = 0; i < binary.length; i++) {
        bytes.push(binary.charCodeAt(i));
      }
      return new TextDecoder().decode(new Uint8Array(bytes));
    } catch (e2) {
      console.error('Fallback decode also failed:', e2);
      throw new Error('Failed to decode data from GitHub');
    }
  }
}

async function ghLoad() {
  try {
    const r = await fetch(
      `https://api.github.com/repos/${GH.owner}/${GH.repo}/contents/${GH_FILE}`,
      { headers: ghHead() }
    );

    if (r.status === 404) {
      ghSha = null;
      return null;
    }

    if (!r.ok) {
      const e = await r.json().catch(() => ({}));
      throw new Error(e.message || `GitHub returned HTTP ${r.status}`);
    }

    const d = await r.json();
    ghSha = d.sha;
    const decoded = fromB64(d.content);
    return JSON.parse(decoded);
  } catch (e) {
    throw e;
  }
}

async function ghSave(data) {
  try {
    const body = {
      message: '[AppName] update',
      content: toB64(JSON.stringify(data, null, 2))
    };
    if (ghSha) body.sha = ghSha;

    const r = await fetch(
      `https://api.github.com/repos/${GH.owner}/${GH.repo}/contents/${GH_FILE}`,
      { method: 'PUT', headers: ghHead(), body: JSON.stringify(body) }
    );

    if (r.status === 409) {
      const latest = await ghLoad();
      const body2 = {
        message: '[AppName] update (merge)',
        content: toB64(JSON.stringify(data, null, 2)),
        sha: ghSha
      };
      const r2 = await fetch(
        `https://api.github.com/repos/${GH.owner}/${GH.repo}/contents/${GH_FILE}`,
        { method: 'PUT', headers: ghHead(), body: JSON.stringify(body2) }
      );
      if (!r2.ok) {
        const e = await r2.json().catch(() => ({}));
        throw new Error(e.message || `HTTP ${r2.status}`);
      }
      const d2 = await r2.json();
      ghSha = d2.content.sha;
      return;
    }

    if (!r.ok) {
      const e = await r.json().catch(() => ({}));
      throw new Error(e.message || `HTTP ${r.status}`);
    }

    const d = await r.json();
    ghSha = d.content.sha;
  } catch (e) {
    throw e;
  }
}

function persist() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(appData));
  if (!isGitHubReady || !GH.owner || !GH.token) return Promise.resolve();

  saveQueue = saveQueue.then(async () => {
    setSyncStatus('syncing', 'Saving...');
    try {
      await ghSave(JSON.parse(JSON.stringify(appData)));
      setSyncStatus('synced', 'Saved ✓');
      setTimeout(() => setSyncStatus('synced', 'Synced'), 2000);
    } catch (e) {
      setSyncStatus('error', 'Save failed');
      showToast('Sync failed', e.message, 'error');
    }
  });
  return saveQueue;
}

